package be.schaubroeck.lpb.rkm.rekenmotor.service;

import be.schaubroeck.context.ConfigConstants;
import be.schaubroeck.context.ExecutionContext;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.exception.MessageException;
import be.schaubroeck.lpb.tools.service.model.GewaarborgdLoonSupplementFilters;
import com.google.common.collect.ArrayListMultimap;
import com.google.common.collect.Multimap;
import com.google.common.collect.Multimaps;
import org.springframework.beans.factory.annotation.Autowired;

import java.util.ArrayList;
import java.util.Collection;
import java.util.Collections;
import java.util.List;
import java.util.Map;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Future;
import java.util.concurrent.atomic.AtomicLong;

public final class GewaarborgdLoonProcesCentral {
    private static final GewaarborgdLoonProcesCentral instance = new GewaarborgdLoonProcesCentral();

    @Autowired
    private ExecutorService procesExecutor;

    private final Map<Long, GewaarborgdLoonSupplementBerekenenProces> processen = new ConcurrentHashMap<>();
    private final Multimap<Integer, GewaarborgdLoonSupplementBerekenenProces> adminToProcessen = Multimaps.synchronizedListMultimap(ArrayListMultimap.create());
    private final AtomicLong procesIdGenerator = new AtomicLong(0);

    private GewaarborgdLoonProcesCentral() {
    }

    public static GewaarborgdLoonProcesCentral getInstance() {
        return instance;
    }

    public List<GewaarborgdLoonSupplementBerekenenProces> getProcessen() {
        return Collections.unmodifiableList(new ArrayList<>(processen.values()));
    }

    public List<GewaarborgdLoonSupplementBerekenenProces> getProcessen(Admin admin) {
        ExecutionContext ec = ExecutionContext.getContext();
        String tenant = ec.getUserAttribute(ConfigConstants.TENANT_EC_ATTR);
        List<GewaarborgdLoonSupplementBerekenenProces> processes = getProcessen();
        List<GewaarborgdLoonSupplementBerekenenProces> result = new ArrayList<>();
        for (GewaarborgdLoonSupplementBerekenenProces proces : processes) {
            if (proces.getAdminId().equals(admin.getId()) && proces.getTenant().equals(tenant)) {
                result.add(proces);
            }
        }
        return result;
    }

    public String startProces(Admin admin, GewaarborgdLoonSupplementFilters filters, GewaarborgdLoonService gewaarborgdLoonService) {
        checkActiveForAdmin(admin);
        Long procesId = procesIdGenerator.incrementAndGet();
        ExecutionContext ec = ExecutionContext.getContext();
        String tenant = ec.getUserAttribute(ConfigConstants.TENANT_EC_ATTR);
        GewaarborgdLoonSupplementBerekenenProces proces =
                new GewaarborgdLoonSupplementBerekenenProces(admin, tenant, filters, gewaarborgdLoonService);
        proces.init(UUID.randomUUID().toString());
        processen.put(procesId, proces);
        adminToProcessen.put(admin.getId(), proces);
        Future<?> future = procesExecutor.submit(proces);
        proces.setFuture(future);
        return proces.getId();
    }

    private void checkActiveForAdmin(Admin admin) {
        Collection<GewaarborgdLoonSupplementBerekenenProces> processenVoorAdmin = adminToProcessen.get(admin.getId());
        for (GewaarborgdLoonSupplementBerekenenProces proces : processenVoorAdmin) {
            if (!proces.isFinished()) {
                throw new MessageException("Er loopt nog een Rekenproces voor deze admin");
            }
        }
    }

    public boolean cancel(Long procesId) {
        GewaarborgdLoonSupplementBerekenenProces proces = processen.get(procesId);
        if (proces != null) {
            proces.halt();
        }
        return false;
    }

    public GewaarborgdLoonSupplementBerekenenProces getProces(Long procesId) {
        return processen.get(procesId);
    }
}
